import { Message, MessageFlag } from "@remit/electrodb-entities";
import { type CreateEntityItem, Entity, type EntityItem } from "electrodb";
import { handleCreateFailed, NotFoundError } from "../error.js";
import { base36uuidv5, REMIT_NAMESPACE } from "../id.js";
import type { ServiceConfig } from "../interfaces.js";
import {
	extractContinuationToken,
	type ResultList,
	resultList,
} from "../pagination.js";

type MessageEntity = Entity<string, string, string, typeof Message>;
type MessageFlagEntity = Entity<string, string, string, typeof MessageFlag>;

export type MessageItem = EntityItem<MessageEntity>;
export type MessageFlagItem = EntityItem<MessageFlagEntity>;

export type CreateMessageInput = Omit<
	CreateEntityItem<MessageEntity>,
	"messageId" | "createdAt" | "updatedAt"
> & { messageId: string };

export type UpdateMessageInput = Partial<
	Omit<CreateMessageInput, "mailboxId" | "uid">
>;

export class MessageService {
	constructor(private config: ServiceConfig) {}

	static generateId(messageIdHeader: string): string {
		return base36uuidv5(messageIdHeader, REMIT_NAMESPACE);
	}

	private get message(): MessageEntity {
		const { client, table } = this.config;
		return new Entity(Message, { client, table });
	}

	private get messageFlag(): MessageFlagEntity {
		const { client, table } = this.config;
		return new Entity(MessageFlag, { client, table });
	}

	async create(input: CreateMessageInput): Promise<MessageItem> {
		const { message } = this;
		return message
			.create(input)
			.go()
			.then((res) => res.data)
			.catch(handleCreateFailed("Message", input));
	}

	async get(messageId: string): Promise<MessageItem> {
		const { message } = this;
		const result = await message.get({ messageId }).go();
		if (!result.data) {
			throw new NotFoundError(`Message not found: ${messageId}`);
		}
		return result.data;
	}

	async update(
		messageId: string,
		input: UpdateMessageInput,
	): Promise<MessageItem> {
		const { message } = this;
		const result = await message
			.patch({ messageId })
			.set(input)
			.go({ response: "all_new" });
		if (!result.data) {
			throw new NotFoundError(`Message not found: ${messageId}`);
		}
		return result.data;
	}

	async delete(messageId: string): Promise<void> {
		const { message } = this;
		await message.delete({ messageId }).go();
	}

	async listByMailbox(
		mailboxId: string,
		options?: { limit?: number; continuationToken?: string },
	): Promise<ResultList<MessageItem>> {
		const { message } = this;
		const { salt = "" } = this.config;
		const cursor = extractContinuationToken(options?.continuationToken, salt);
		const result = await message.query.byMailboxId({ mailboxId }).go({
			limit: options?.limit,
			cursor,
		});
		return resultList(result.data, result.cursor, salt);
	}
}
