import { Account, Mailbox } from "@remit/electrodb-entities";
import {
	type CreateEntityItem,
	Entity,
	type EntityItem,
	Service,
} from "electrodb";
import { handleCreateFailed, NotFoundError } from "../error.js";
import { base36uuid } from "../id.js";
import type { ServiceConfig } from "../interfaces.js";
import {
	extractContinuationToken,
	type ResultList,
	resultList,
} from "../pagination.js";

type AccountEntity = Entity<string, string, string, typeof Account>;
type MailboxEntity = Entity<string, string, string, typeof Mailbox>;

export type AccountItem = EntityItem<AccountEntity>;
export type MailboxItem = EntityItem<MailboxEntity>;

export type CreateAccountInput = Omit<
	CreateEntityItem<AccountEntity>,
	"accountId" | "createdAt" | "updatedAt"
>;
export type UpdateAccountInput = Partial<
	Omit<CreateAccountInput, "accountConfigId">
>;

export type AccountDescription = {
	account: AccountItem[];
	mailbox: MailboxItem[];
};

export class AccountService {
	constructor(private config: ServiceConfig) {}

	private get account(): AccountEntity {
		const { client, table } = this.config;
		return new Entity(Account, { client, table });
	}

	private get mailbox(): MailboxEntity {
		const { client, table } = this.config;
		return new Entity(Mailbox, { client, table });
	}

	private get accountService() {
		const { client, table } = this.config;
		const { account, mailbox } = this;
		return new Service({ account, mailbox }, { client, table });
	}

	async create(input: CreateAccountInput): Promise<AccountItem> {
		const { account } = this;
		const accountId = base36uuid();
		return account
			.create({ ...input, accountId })
			.go()
			.then((res) => res.data)
			.catch(handleCreateFailed("Account", input));
	}

	async get(accountId: string): Promise<AccountItem> {
		const { account } = this;
		const result = await account.get({ accountId }).go();
		if (!result.data) {
			throw new NotFoundError(`Account not found: ${accountId}`);
		}
		return result.data;
	}

	async update(
		accountId: string,
		input: UpdateAccountInput,
	): Promise<AccountItem> {
		const { account } = this;
		const result = await account
			.patch({ accountId })
			.set(input)
			.go({ response: "all_new" });
		if (!result.data) {
			throw new NotFoundError(`Account not found: ${accountId}`);
		}
		return result.data;
	}

	async delete(accountId: string): Promise<void> {
		const { account } = this;
		await account.delete({ accountId }).go();
	}

	async list(
		accountConfigId: string,
		options?: { limit?: number; continuationToken?: string },
	): Promise<ResultList<AccountItem>> {
		const { account } = this;
		const { salt = "" } = this.config;
		const cursor = extractContinuationToken(options?.continuationToken, salt);
		const result = await account.query
			.byAccountConfigId({ accountConfigId })
			.go({
				limit: options?.limit,
				cursor,
			});
		return resultList(result.data, result.cursor, salt);
	}

	async describe(accountId: string): Promise<AccountDescription> {
		const { accountService } = this;
		const result = await accountService.collections
			.account({ accountId })
			.go({ pages: "all" });
		if (result.data.account.length === 0) {
			throw new NotFoundError(`Account not found: ${accountId}`);
		}
		return result.data;
	}
}
