import { Account, AccountConfig, Address } from "@remit/electrodb-entities";
import {
	type CreateEntityItem,
	Entity,
	type EntityItem,
	Service,
} from "electrodb";
import { handleCreateFailed, NotFoundError } from "../error.js";
import { base36uuid } from "../id.js";
import type { ServiceConfig } from "../interfaces.js";
import {
	extractContinuationToken,
	type ResultList,
	resultList,
} from "../pagination.js";

type AccountConfigEntity = Entity<string, string, string, typeof AccountConfig>;
type AccountEntity = Entity<string, string, string, typeof Account>;
type AddressEntity = Entity<string, string, string, typeof Address>;

export type AccountConfigItem = EntityItem<AccountConfigEntity>;
export type AccountItem = EntityItem<AccountEntity>;
export type AddressItem = EntityItem<AddressEntity>;

export type CreateAccountConfigInput = Omit<
	CreateEntityItem<AccountConfigEntity>,
	"accountConfigId" | "createdAt" | "updatedAt"
>;
export type UpdateAccountConfigInput = Partial<
	Omit<CreateAccountConfigInput, "userId">
>;

export type AccountConfigDescription = {
	accountConfig: AccountConfigItem[];
	account: AccountItem[];
	address: AddressItem[];
};

export class AccountConfigService {
	constructor(private config: ServiceConfig) {}

	private get accountConfig(): AccountConfigEntity {
		const { client, table } = this.config;
		return new Entity(AccountConfig, { client, table });
	}

	private get account(): AccountEntity {
		const { client, table } = this.config;
		return new Entity(Account, { client, table });
	}

	private get address(): AddressEntity {
		const { client, table } = this.config;
		return new Entity(Address, { client, table });
	}

	private get accountConfigService() {
		const { client, table } = this.config;
		const { accountConfig, account, address } = this;
		return new Service({ accountConfig, account, address }, { client, table });
	}

	async create(input: CreateAccountConfigInput): Promise<AccountConfigItem> {
		const { accountConfig } = this;
		const accountConfigId = base36uuid();
		return accountConfig
			.create({ ...input, accountConfigId })
			.go()
			.then((res) => res.data)
			.catch(handleCreateFailed("AccountConfig", input));
	}

	async get(accountConfigId: string): Promise<AccountConfigItem> {
		const { accountConfig } = this;
		const result = await accountConfig.get({ accountConfigId }).go();
		if (!result.data) {
			throw new NotFoundError(`AccountConfig not found: ${accountConfigId}`);
		}
		return result.data;
	}

	async update(
		accountConfigId: string,
		input: UpdateAccountConfigInput,
	): Promise<AccountConfigItem> {
		const { accountConfig } = this;
		const result = await accountConfig
			.patch({ accountConfigId })
			.set(input)
			.go({ response: "all_new" });
		if (!result.data) {
			throw new NotFoundError(`AccountConfig not found: ${accountConfigId}`);
		}
		return result.data;
	}

	async delete(accountConfigId: string): Promise<void> {
		const { accountConfig } = this;
		await accountConfig.delete({ accountConfigId }).go();
	}

	async listByUser(
		userId: string,
		options?: { limit?: number; continuationToken?: string },
	): Promise<ResultList<AccountConfigItem>> {
		const { accountConfig } = this;
		const { salt = "" } = this.config;
		const cursor = extractContinuationToken(options?.continuationToken, salt);
		const result = await accountConfig.query.byUserId({ userId }).go({
			limit: options?.limit,
			cursor,
		});
		return resultList(result.data, result.cursor, salt);
	}

	async describe(accountConfigId: string): Promise<AccountConfigDescription> {
		const { accountConfigService } = this;
		const result = await accountConfigService.collections
			.accountConfig({ accountConfigId })
			.go({ pages: "all" });
		if (result.data.accountConfig.length === 0) {
			throw new NotFoundError(`AccountConfig not found: ${accountConfigId}`);
		}
		return result.data;
	}
}
