import { Mailbox } from "@remit/electrodb-entities";
import { type CreateEntityItem, Entity, type EntityItem } from "electrodb";
import { handleCreateFailed, NotFoundError } from "../error.js";
import { base36uuid } from "../id.js";
import type { ServiceConfig } from "../interfaces.js";
import {
	extractContinuationToken,
	type ResultList,
	resultList,
} from "../pagination.js";

type MailboxEntity = Entity<string, string, string, typeof Mailbox>;

export type MailboxItem = EntityItem<MailboxEntity>;

export type CreateMailboxInput = Omit<
	CreateEntityItem<MailboxEntity>,
	"mailboxId" | "createdAt" | "updatedAt"
>;
export type UpdateMailboxInput = Partial<Omit<CreateMailboxInput, "accountId">>;

export class MailboxService {
	constructor(private config: ServiceConfig) {}

	private get mailbox(): MailboxEntity {
		const { client, table } = this.config;
		return new Entity(Mailbox, { client, table });
	}

	async create(input: CreateMailboxInput): Promise<MailboxItem> {
		const { mailbox } = this;
		const mailboxId = base36uuid();
		return mailbox
			.create({ ...input, mailboxId })
			.go()
			.then((res) => res.data)
			.catch(handleCreateFailed("Mailbox", input));
	}

	async get(mailboxId: string): Promise<MailboxItem> {
		const { mailbox } = this;
		const result = await mailbox.get({ mailboxId }).go();
		if (!result.data) {
			throw new NotFoundError(`Mailbox not found: ${mailboxId}`);
		}
		return result.data;
	}

	async update(
		mailboxId: string,
		input: UpdateMailboxInput,
	): Promise<MailboxItem> {
		const { mailbox } = this;
		const result = await mailbox
			.patch({ mailboxId })
			.set(input)
			.go({ response: "all_new" });
		if (!result.data) {
			throw new NotFoundError(`Mailbox not found: ${mailboxId}`);
		}
		return result.data;
	}

	async delete(mailboxId: string): Promise<void> {
		const { mailbox } = this;
		await mailbox.delete({ mailboxId }).go();
	}

	async listByAccount(
		accountId: string,
		options?: { limit?: number; continuationToken?: string },
	): Promise<ResultList<MailboxItem>> {
		const { mailbox } = this;
		const { salt = "" } = this.config;
		const cursor = extractContinuationToken(options?.continuationToken, salt);
		const result = await mailbox.query.byAccountId({ accountId }).go({
			limit: options?.limit,
			cursor,
		});
		return resultList(result.data, result.cursor, salt);
	}
}
