import {
	BodyPart,
	BodyPartContent,
	BodyPartParameter,
	BodyPartStorage,
	Envelope,
	EnvelopeAddress,
	MessageReference,
	RawMessageStorage,
} from "@remit/electrodb-entities";
import {
	type CreateEntityItem,
	Entity,
	type EntityItem,
	Service,
} from "electrodb";
import { handleCreateFailed, NotFoundError } from "../error.js";
import { base36uuidv5, REMIT_NAMESPACE } from "../id.js";
import type { ServiceConfig } from "../interfaces.js";

type EnvelopeEntity = Entity<string, string, string, typeof Envelope>;
type MessageReferenceEntity = Entity<
	string,
	string,
	string,
	typeof MessageReference
>;
type EnvelopeAddressEntity = Entity<
	string,
	string,
	string,
	typeof EnvelopeAddress
>;
type BodyPartEntity = Entity<string, string, string, typeof BodyPart>;
type BodyPartParameterEntity = Entity<
	string,
	string,
	string,
	typeof BodyPartParameter
>;
type RawMessageStorageEntity = Entity<
	string,
	string,
	string,
	typeof RawMessageStorage
>;
type BodyPartStorageEntity = Entity<
	string,
	string,
	string,
	typeof BodyPartStorage
>;
type BodyPartContentEntity = Entity<
	string,
	string,
	string,
	typeof BodyPartContent
>;

export type EnvelopeItem = EntityItem<EnvelopeEntity>;
export type MessageReferenceItem = EntityItem<MessageReferenceEntity>;
export type EnvelopeAddressItem = EntityItem<EnvelopeAddressEntity>;
export type BodyPartItem = EntityItem<BodyPartEntity>;
export type BodyPartParameterItem = EntityItem<BodyPartParameterEntity>;
export type RawMessageStorageItem = EntityItem<RawMessageStorageEntity>;
export type BodyPartStorageItem = EntityItem<BodyPartStorageEntity>;
export type BodyPartContentItem = EntityItem<BodyPartContentEntity>;

export type CreateEnvelopeInput = Omit<
	CreateEntityItem<EnvelopeEntity>,
	"envelopeId" | "createdAt" | "updatedAt"
> & { envelopeId: string };

export type UpdateEnvelopeInput = Partial<
	Omit<CreateEnvelopeInput, "messageId">
>;

export type MessageData = {
	envelope: EnvelopeItem[];
	messageReference: MessageReferenceItem[];
	envelopeAddress: EnvelopeAddressItem[];
	bodyPart: BodyPartItem[];
	bodyPartParameter: BodyPartParameterItem[];
	rawMessageStorage: RawMessageStorageItem[];
	bodyPartStorage: BodyPartStorageItem[];
	bodyPartContent: BodyPartContentItem[];
};

export class EnvelopeService {
	constructor(private config: ServiceConfig) {}

	static generateId(messageId: string): string {
		return base36uuidv5(messageId, REMIT_NAMESPACE);
	}

	private get envelope(): EnvelopeEntity {
		const { client, table } = this.config;
		return new Entity(Envelope, { client, table });
	}

	private get messageReference(): MessageReferenceEntity {
		const { client, table } = this.config;
		return new Entity(MessageReference, { client, table });
	}

	private get envelopeAddress(): EnvelopeAddressEntity {
		const { client, table } = this.config;
		return new Entity(EnvelopeAddress, { client, table });
	}

	private get bodyPart(): BodyPartEntity {
		const { client, table } = this.config;
		return new Entity(BodyPart, { client, table });
	}

	private get bodyPartParameter(): BodyPartParameterEntity {
		const { client, table } = this.config;
		return new Entity(BodyPartParameter, { client, table });
	}

	private get rawMessageStorage(): RawMessageStorageEntity {
		const { client, table } = this.config;
		return new Entity(RawMessageStorage, { client, table });
	}

	private get bodyPartStorage(): BodyPartStorageEntity {
		const { client, table } = this.config;
		return new Entity(BodyPartStorage, { client, table });
	}

	private get bodyPartContent(): BodyPartContentEntity {
		const { client, table } = this.config;
		return new Entity(BodyPartContent, { client, table });
	}

	private get messageDataService() {
		const { client, table } = this.config;
		const {
			envelope,
			messageReference,
			envelopeAddress,
			bodyPart,
			bodyPartParameter,
			rawMessageStorage,
			bodyPartStorage,
			bodyPartContent,
		} = this;
		return new Service(
			{
				envelope,
				messageReference,
				envelopeAddress,
				bodyPart,
				bodyPartParameter,
				rawMessageStorage,
				bodyPartStorage,
				bodyPartContent,
			},
			{ client, table },
		);
	}

	async createEnvelope(input: CreateEnvelopeInput): Promise<EnvelopeItem> {
		const { envelope } = this;
		return envelope
			.create(input)
			.go()
			.then((res) => res.data)
			.catch(handleCreateFailed("Envelope", input));
	}

	async getEnvelope(envelopeId: string): Promise<EnvelopeItem> {
		const { envelope } = this;
		const result = await envelope.get({ envelopeId }).go();
		if (!result.data) {
			throw new NotFoundError(`Envelope not found: ${envelopeId}`);
		}
		return result.data;
	}

	async updateEnvelope(
		envelopeId: string,
		input: UpdateEnvelopeInput,
	): Promise<EnvelopeItem> {
		const { envelope } = this;
		const result = await envelope
			.patch({ envelopeId })
			.set(input)
			.go({ response: "all_new" });
		if (!result.data) {
			throw new NotFoundError(`Envelope not found: ${envelopeId}`);
		}
		return result.data;
	}

	async deleteEnvelope(envelopeId: string): Promise<void> {
		const { envelope } = this;
		await envelope.delete({ envelopeId }).go();
	}

	async getMessageData(messageId: string): Promise<MessageData> {
		const { messageDataService } = this;
		const result = await messageDataService.collections
			.messageData({ messageId })
			.go({ pages: "all" });
		if (result.data.envelope.length === 0) {
			throw new NotFoundError(`Message data not found: ${messageId}`);
		}
		return result.data;
	}
}
