import { Address, EnvelopeAddress } from "@remit/electrodb-entities";
import { type CreateEntityItem, Entity, type EntityItem } from "electrodb";
import { handleCreateFailed, NotFoundError } from "../error.js";
import { base36uuidv5, REMIT_NAMESPACE } from "../id.js";
import type { ServiceConfig } from "../interfaces.js";
import {
	extractContinuationToken,
	type ResultList,
	resultList,
} from "../pagination.js";

type AddressEntity = Entity<string, string, string, typeof Address>;
type EnvelopeAddressEntity = Entity<
	string,
	string,
	string,
	typeof EnvelopeAddress
>;

export type AddressItem = EntityItem<AddressEntity>;
export type EnvelopeAddressItem = EntityItem<EnvelopeAddressEntity>;

export type CreateAddressInput = Omit<
	CreateEntityItem<AddressEntity>,
	"addressId" | "createdAt" | "updatedAt"
> & { addressId: string };

export type UpdateAddressInput = Partial<
	Omit<CreateAddressInput, "accountConfigId">
>;

export type CreateEnvelopeAddressInput = Omit<
	CreateEntityItem<EnvelopeAddressEntity>,
	"envelopeAddressId" | "createdAt" | "updatedAt"
> & { envelopeAddressId: string };

export class AddressService {
	constructor(private config: ServiceConfig) {}

	static generateAddressId(accountConfigId: string, email: string): string {
		return base36uuidv5(
			`${accountConfigId}:${email.toLowerCase()}`,
			REMIT_NAMESPACE,
		);
	}

	static generateEnvelopeAddressId(
		messageId: string,
		role: string,
		order: number,
	): string {
		return base36uuidv5(`${messageId}:${role}:${order}`, REMIT_NAMESPACE);
	}

	private get address(): AddressEntity {
		const { client, table } = this.config;
		return new Entity(Address, { client, table });
	}

	private get envelopeAddress(): EnvelopeAddressEntity {
		const { client, table } = this.config;
		return new Entity(EnvelopeAddress, { client, table });
	}

	async createAddress(input: CreateAddressInput): Promise<AddressItem> {
		const { address } = this;
		return address
			.create(input)
			.go()
			.then((res) => res.data)
			.catch(handleCreateFailed("Address", input));
	}

	async getAddress(addressId: string): Promise<AddressItem> {
		const { address } = this;
		const result = await address.get({ addressId }).go();
		if (!result.data) {
			throw new NotFoundError(`Address not found: ${addressId}`);
		}
		return result.data;
	}

	async updateAddress(
		addressId: string,
		input: UpdateAddressInput,
	): Promise<AddressItem> {
		const { address } = this;
		const result = await address
			.patch({ addressId })
			.set(input)
			.go({ response: "all_new" });
		if (!result.data) {
			throw new NotFoundError(`Address not found: ${addressId}`);
		}
		return result.data;
	}

	async deleteAddress(addressId: string): Promise<void> {
		const { address } = this;
		await address.delete({ addressId }).go();
	}

	async listByAccountConfig(input: {
		accountConfigId: string;
		normalizedCompound?: string;
		cursor?: string;
		limit?: number;
	}): Promise<ResultList<AddressItem>> {
		const { address } = this;
		const { salt = "" } = this.config;
		const { accountConfigId, normalizedCompound, cursor, limit } = input;

		const options = {
			cursor: extractContinuationToken(cursor, salt),
			limit: limit || 100,
		};

		if (normalizedCompound) {
			return address.query
				.byAccountConfigId({ accountConfigId })
				.begins({ normalizedCompound })
				.go(options)
				.then((res) => resultList(res.data, res.cursor, salt));
		}

		return address.query
			.byAccountConfigId({ accountConfigId })
			.go(options)
			.then((res) => resultList(res.data, res.cursor, salt));
	}

	async createEnvelopeAddress(
		input: CreateEnvelopeAddressInput,
	): Promise<EnvelopeAddressItem> {
		const { envelopeAddress } = this;
		return envelopeAddress
			.create(input)
			.go()
			.then((res) => res.data)
			.catch(handleCreateFailed("EnvelopeAddress", input));
	}

	async getEnvelopeAddress(
		envelopeAddressId: string,
	): Promise<EnvelopeAddressItem> {
		const { envelopeAddress } = this;
		const result = await envelopeAddress.get({ envelopeAddressId }).go();
		if (!result.data) {
			throw new NotFoundError(
				`EnvelopeAddress not found: ${envelopeAddressId}`,
			);
		}
		return result.data;
	}

	async deleteEnvelopeAddress(envelopeAddressId: string): Promise<void> {
		const { envelopeAddress } = this;
		await envelopeAddress.delete({ envelopeAddressId }).go();
	}
}
